patch:
diff --git a/llvm/lib/Transforms/Vectorize/VectorCombine.cpp b/llvm/lib/Transforms/Vectorize/VectorCombine.cpp
index 45330e548bc29..17f43c0d960bd 100644
--- a/llvm/lib/Transforms/Vectorize/VectorCombine.cpp
+++ b/llvm/lib/Transforms/Vectorize/VectorCombine.cpp
@@ -175,6 +175,17 @@ class VectorCombine {
     }
   }

+  // Erase an already-dead instruction, keeping run()'s iteration cursor valid.
+  // Unlike eraseInstruction(), does not recursively delete operands, so callers
+  // can erase a group of related instructions in a fixed order.
+  void eraseDeadInstruction(Instruction &I) {
+    assert(I.use_empty() && "erasing instruction with remaining uses");
+    if (NextInst == &I)
+      NextInst = NextInst->getNextNode();
+    Worklist.remove(&I);
+    I.eraseFromParent();
+  }
+
   void eraseInstruction(Instruction &I) {
     LLVM_DEBUG(dbgs() << "VC: Erasing: " << I << '\n');
     SmallVector<Value *> Ops(I.operands());
@@ -2067,6 +2078,11 @@ bool VectorCombine::scalarizeLoadExtract(LoadInst *LI, VectorType *VecTy,
   if (!TTI.allowVectorElementIndexingUsingGEP())
     return false;

+  Type *ElemType = VecTy->getElementType();
+  // Do not turn one atomic load into multiple atomic loads.
+  if (LI->isAtomic() && !LI->hasOneUse())
+    return false;
+
   DenseMap<ExtractElementInst *, ScalarizationResult> NeedFreeze;
   llvm::scope_exit FailureGuard([&]() {
     // If the transform is aborted, discard the ScalarizationResults.
@@ -2109,13 +2125,8 @@ bool VectorCombine::scalarizeLoadExtract(LoadInst *LI, VectorType *VecTy,
   if (ScalarizedCost >= OriginalCost)
     return false;

-  // Ensure we add the load back to the worklist BEFORE its users so they can
-  // erased in the correct order.
-  Worklist.push(LI);
-
-  Type *ElemType = VecTy->getElementType();
-
   // Replace extracts with narrow scalar loads.
+  SmallVector<Instruction *> ToErase;
   for (User *U : LI->users()) {
     auto *EI = cast<ExtractElementInst>(U);
     Value *Idx = EI->getIndexOperand();
@@ -2134,6 +2145,8 @@ bool VectorCombine::scalarizeLoadExtract(LoadInst *LI, VectorType *VecTy,
     Align ScalarOpAlignment =
         computeAlignmentAfterScalarization(LI->getAlign(), ElemType, Idx, *DL);
     NewLoad->setAlignment(ScalarOpAlignment);
+    if (LI->isAtomic())
+      NewLoad->setAtomic(LI->getOrdering(), LI->getSyncScopeID());

     if (auto *ConstIdx = dyn_cast<ConstantInt>(Idx)) {
       size_t Offset = ConstIdx->getZExtValue() * DL->getTypeStoreSize(ElemType);
@@ -2142,8 +2155,15 @@ bool VectorCombine::scalarizeLoadExtract(LoadInst *LI, VectorType *VecTy,
     }

     replaceValue(*EI, *NewLoad, false);
+    ToErase.push_back(EI);
   }

+  // Erase explicitly; an ordered atomic load is not trivially dead, so worklist
+  // DCE would leave it behind, duplicating the original atomic access.
+  for (Instruction *EI : ToErase)
+    eraseDeadInstruction(*EI);
+  eraseDeadInstruction(*LI);
+
   FailureGuard.release();
   return true;
 }
@@ -2195,22 +2215,28 @@ bool VectorCombine::scalarizeLoadBitcast(LoadInst *LI, VectorType *VecTy,
   if (ScalarizedCost >= OriginalCost)
     return false;

-  // Ensure we add the load back to the worklist BEFORE its users so they can
-  // erased in the correct order.
-  Worklist.push(LI);
-
   Builder.SetInsertPoint(LI);
   auto *ScalarLoad =
       Builder.CreateLoad(TargetScalarType, Ptr, LI->getName() + ".scalar");
   ScalarLoad->setAlignment(LI->getAlign());
+  if (LI->isAtomic())
+    ScalarLoad->setAtomic(LI->getOrdering(), LI->getSyncScopeID());
   ScalarLoad->copyMetadata(*LI);

   // Replace all bitcast users with the scalar load.
+  SmallVector<Instruction *> ToErase;
   for (User *U : LI->users()) {
     auto *BC = cast<BitCastInst>(U);
     replaceValue(*BC, *ScalarLoad, false);
+    ToErase.push_back(BC);
   }

+  // Erase explicitly; an ordered atomic load is not trivially dead, so worklist
+  // DCE would leave it behind, duplicating the original atomic access.
+  for (Instruction *BC : ToErase)
+    eraseDeadInstruction(*BC);
+  eraseDeadInstruction(*LI);
+
   return true;
 }

tests.test_body:
define i32 @scalarize_atomic_extract_monotonic(ptr %p) {
  %load = load atomic <2 x i32>, ptr %p monotonic, align 8
  %extract = extractelement <2 x i32> %load, i64 0
  ret i32 %extract
}

define i32 @scalarize_atomic_extract_syncscope(ptr %p) {
  %load = load atomic <2 x i32>, ptr %p syncscope("singlethread") acquire, align 8
  %extract = extractelement <2 x i32> %load, i64 0
  ret i32 %extract
}

define i64 @scalarize_atomic_bitcast(ptr %p) {
  %load = load atomic <2 x i32>, ptr %p seq_cst, align 8
  %bitcast = bitcast <2 x i32> %load to i64
  ret i64 %bitcast
}

define i64 @scalarize_atomic_bitcast_monotonic(ptr %p) {
  %load = load atomic <2 x i32>, ptr %p syncscope("singlethread") monotonic, align 8
  %bitcast = bitcast <2 x i32> %load to i64
  ret i64 %bitcast
}

define i32 @scalarize_atomic_extract(ptr %p) {
  %load = load atomic <2 x i32>, ptr %p seq_cst, align 8
  %extract = extractelement <2 x i32> %load, i64 0
  ret i32 %extract
}
